/**
 *  This module contains the {@link TimePickerComponent|`TimePickerComponent`} and related classes.
 *
 *  @module
 */
import {Component, forwardRef, HostBinding, HostListener, Input} from '@angular/core';
import {ControlValueAccessor, FormControl, NG_VALUE_ACCESSOR, ReactiveFormsModule} from '@angular/forms';
import {DateTime} from 'luxon';
import {MatRipple} from '@angular/material/core';

/** The digits to show in the dial when the phase is {@link Phase.HOURS|`HOURS`}. */
const HOUR_DIGITS   = new Array(12).fill(0).map((_, i) => i + 1);
/** The digits to show in the dial when the phase is {@link Phase.MINUTES|`MINUTES`} or {@link Phase.SECONDS|`SECONDS`}. */
const MINUTE_DIGITS = new Array(12).fill(0).map((_, i) => ((i + 1) * 5) % 60);

/**
 * A component that displays a time picker to select a time value (from 00:00:00 to 23:59:59), in AM/PM format.
 *
 * This component displays a digital representation of the selected time, and a dial for the selection, following
 * the <a href="https://m3.material.io/components/time-pickers/specs">Material Design specifications for a time picker</a>.
 * The dial can be clicked to select the time, and advances in the cycle hour → minute → second → hour. Fast
 * switch between these can be achieved by clicking on the digit group above.
 *
 * <img class="show-dark" src="data:image/png;base64,">
 * <img class="show-light" src="data:image/png;base64,">
 * The component.
 *
 * @component
 * @componentSelector `<house-mix-time-picker>`
 */
@Component({
               selector:    'house-mix-time-picker',
               imports:     [
                   ReactiveFormsModule,
                   MatRipple
               ],
               providers:   [
                   {
                       provide:     NG_VALUE_ACCESSOR,
                       useExisting: forwardRef(() => TimePickerComponent),
                       multi:       true
                   }
               ],
               templateUrl: './time-picker.component.html',
               styleUrl:    './time-picker.component.scss'
           })
export class TimePickerComponent implements ControlValueAccessor {

    /** The time element currently being edited in the dial. */
    protected phase: Phase = Phase.HOURS;

    /** The selected hours value. */
    protected hour: number | null   = null;
    /** The selected minutes value. */
    protected minute: number | null = null;
    /** The selected seconds value. */
    protected second: number | null = null;

    /** The form control handling the selected time. */
    protected timeFormControl: FormControl<DateTime | null> = new FormControl<DateTime | null>(null);

    /** The half of the day the 12-hour clock is referencing. */
    private _dayHalf: 'AM' | 'PM' = 'AM';

    /**
     * Creates an instance of the component. Do not call this constructor directly,
     * it's handled by Angular's rendering engine or component factory.
     */
    constructor() {
        this.formControl = this.timeFormControl;
    }

    /**
     * The {@link FormControl|`FormControl`} that controls the value of the component.
     *
     * @input
     * @group Component inputs
     */
    @Input()
    public set formControl(formControl: FormControl<DateTime | null>) {
        this.timeFormControl = formControl;
        this.timeFormControl.valueChanges.subscribe(value => {
            this.hour     = value != null ? ((value.hour % 12) == 0 ? 12 : (value.hour % 12)) : null;
            this._dayHalf = (value?.hour ?? 1) < 12 ? 'AM' : 'PM';
            this.minute   = value?.minute ?? null;
            this.second   = value?.second ?? null;
        });
    }

    /** Whether dragging of the hand on the dial is in progress. */
    private dragging = false;

    /**
     * Set which half of the day the 12-hour clock is referencing.
     *
     * @param {"AM" | "PM"} dayHalf - The half of the day to switch to.
     */
    protected set dayHalf(dayHalf: 'AM' | 'PM') {
        this._dayHalf = dayHalf;
        this.updateFormControl();
    }

    /**
     * The half of the day the 12-hour clock is referencing.
     */
    protected get dayHalf(): 'AM' | 'PM' {
        return this._dayHalf;
    }

    /**
     * Update the form control building the time from the single selected values.
     */
    private updateFormControl(): void {
        if (this.hour != null && this.minute != null && this.second != null) {
            let hour = this.hour;
            if (this.dayHalf == 'PM') {
                if (hour != 12) {
                    hour += 12;
                }
            } else if (hour == 12) {
                hour = 0;
            }
            this.timeFormControl.setValue(
                DateTime.fromJSDate(
                    new Date(
                        2000,
                        0,
                        1,
                        hour,
                        this.minute,
                        this.second
                    )
                )
            );
        }
    }

    /**
     * Mouse down event on the dial.
     *
     * @param {MouseEvent} event - The DOM event.
     */
    protected mouseDown(event: MouseEvent): void {
        this.dragging = true;
        this.mouseMove(event);
    }

    /**
     * Mouse move event on the dial.
     *
     * @param {MouseEvent} event - The DOM event.
     */
    protected mouseMove(event: MouseEvent): void {
        if (this.dragging && this.timeFormControl.enabled) {
            const boundingClientRect = (event.target as HTMLElement).getBoundingClientRect();
            const x                  = ((event.clientX - boundingClientRect.x) / boundingClientRect.width - 0.5) * 2;
            const y                  = ((event.clientY - boundingClientRect.y) / boundingClientRect.height - 0.5) * 2;
            const rotationFraction   = (Math.atan2(y, x) / (2 * Math.PI) + 1.25) % 1;
            if (this.phase == Phase.HOURS) {
                let hours = Math.round(rotationFraction * 12);
                if (hours == 0) {
                    hours = 12;
                }
                this.hour = hours;
            } else if (this.phase == Phase.MINUTES) {
                this.minute = Math.round(rotationFraction * 60);
            } else {
                this.second = Math.round(rotationFraction * 60);
            }
            this.updateFormControl();
        }
    }

    /**
     * Mouse up event on the dial.
     *
     * @param {MouseEvent} event - The DOM event.
     */
    protected mouseUp(event: MouseEvent): void {
        this.mouseMove(event);
        this.dragging = false;
        if (this.timeFormControl.enabled) {
            if (this.phase == Phase.HOURS) {
                this.phase = Phase.MINUTES;
            } else if (this.phase == Phase.MINUTES) {
                this.phase = Phase.SECONDS;
            } else {
                this.phase = Phase.HOURS;
            }
        }
    }

    /**
     * Whether the component is disabled.
     *
     * @hostBinding class.disabled
     */
    @HostBinding('class.disabled')
    public get isDisabled(): boolean {
        return this.timeFormControl.disabled;
    }

    /** The blur event handler. */
    @HostListener('blur')
    public onBlur(): void {
        this.onTouched?.();
    }

    /**
     * Implementation of {@link ControlValueAccessor#writeValue| `ControlValueAccessor.writeValue()`}.
     *
     * @param {DateTime} time - The value to write.
     */
    public writeValue(time: DateTime): void {
        this.hour     = time.hour;
        this._dayHalf = "AM";
        if (this.hour == 0) {
            this.hour = 12;
        } else if (this.hour == 12) {
            this._dayHalf = "PM";
        } else if (this.hour > 12) {
            this.hour -= 12;
            this._dayHalf = "PM";
        }
        this.minute   = time.minute;
        this.second   = time.second;
        this.updateFormControl();
    }

    /**
     * Touched listener for {@link TimePickerComponent#registerOnTouched| `registerOnTouched()`}.
     */
    private onTouched: (() => void) | null                      = null;
    /**
     * Change listener for {@link TimePickerComponent#registerOnChange| `registerOnChange()`}.
     */
    private onChange: ((value: DateTime | null) => void) | null = null;

    /**
     * Implementation of {@link ControlValueAccessor#registerOnChange| `ControlValueAccessor.registerOnChange()`}.
     *
     * @param {(value: DateTime) => void} fn - The listener.
     */
    public registerOnChange(fn: (value: DateTime | null) => void): void {
        this.onChange = fn;
    }

    /**
     * Implementation of {@link ControlValueAccessor#registerOnTouched| `ControlValueAccessor.registerOnTouched()`}.
     *
     * @param {() => void} fn - The listener.
     */
    public registerOnTouched(fn: () => void): void {
        this.onTouched = fn;
    }

    /**
     * Implementation of {@link ControlValueAccessor#setDisabledState| `ControlValueAccessor.setDisabledState()`}.
     *
     * @param {boolean} isDisabled - The value.
     */
    public setDisabledState?(isDisabled: boolean): void {
        if (isDisabled) {
            this.timeFormControl.disable();
        } else {
            this.timeFormControl.enable();
        }
    }

    /** @ignore */
    protected HOURS          = HOUR_DIGITS;
    /** @ignore */
    protected MINUTES        = MINUTE_DIGITS;
    /** @ignore */
    protected readonly Math  = Math;
    /** @ignore */
    protected readonly Phase = Phase;
}

/**
 * Which phase of the {@link TimePickerComponent|`TimePickerComponent`} is being edited.
 *
 * @notExported
 */
enum Phase {
    /** The dial is showing the hours. */
    HOURS,
    /** The dial is showing the minutes. */
    MINUTES,
    /** The dial is showing the seconds. */
    SECONDS
}
